import { Link } from "react-router-dom";

export default function Logo({ className = "" }) {
    return (
        <Link 
            to="/" 
            className={`flex items-center gap-2 group transition-transform hover:scale-105 ${className}`}
        >
            {/* Logo Image */}
            <img 
                src="/shoplivebharat-logo.svg" 
                alt="ShopLiveBharat" 
                className="h-12 md:h-14 w-auto"
            />
        </Link>
    );
}
